from math import gcd
class Solution:
    def totalBeauty(self, nums):
        MOD = 10**9 + 7
        n = len(nums)
        ans = 0
        dp = [None] * n
        for i in range(n):
            d = {nums[i]: 1}
            for j in range(i):
                if nums[j] < nums[i]:
                    for g, c in dp[j].items():
                        ng = gcd(g, nums[i])
                        d[ng] = (d.get(ng, 0) + c) % MOD
            dp[i] = d
            for g, c in d.items():
                ans = (ans + g * c) % MOD
        return ans % MOD

