class Solution:
    def totalBeauty(self, nums):
        MOD = 10**9 + 7
        M = max(nums)
        from collections import defaultdict
        pos = defaultdict(list)
        for idx, v in enumerate(nums):
            pos[v].append(idx)
        cntM = [0] * (M + 1)
        for g in range(1, M + 1):
            lst = []
            m = g
            while m <= M:
                for idx in pos.get(m, ()):
                    lst.append((idx, m))
                m += g
            if not lst:
                continue
            lst.sort()
            vals = sorted(set(v for _, v in lst))
            comp = {v: i + 1 for i, v in enumerate(vals)}
            size = len(vals)
            bit = [0] * (size + 1)
            def upd(i, x):
                while i <= size:
                    bit[i] = (bit[i] + x) % MOD
                    i += i & -i
            def qry(i):
                s = 0
                while i > 0:
                    s = (s + bit[i]) % MOD
                    i -= i & -i
                return s
            tot = 0
            for idx, v in lst:
                c = comp[v]
                dp = (1 + qry(c - 1)) % MOD
                tot = (tot + dp) % MOD
                upd(c, dp)
            cntM[g] = tot
        exact = [0] * (M + 1)
        for g in range(M, 0, -1):
            e = cntM[g]
            m = 2 * g
            while m <= M:
                e = (e - exact[m]) % MOD
                m += g
            exact[g] = e % MOD
        ans = 0
        for g in range(1, M + 1):
            ans = (ans + g * exact[g]) % MOD
        return ans % MOD

