var totalBeauty = function(nums) {
    const MOD = 1000000007n;
    const M = Math.max(...nums);
    const pos = new Map();
    for (let idx = 0; idx < nums.length; idx++) {
        const v = nums[idx];
        if (!pos.has(v)) pos.set(v, []);
        pos.get(v).push(idx);
    }
    const cntM = new Array(M + 1).fill(0n);
    for (let g = 1; g <= M; g++) {
        const lst = [];
        for (let m = g; m <= M; m += g) {
            const arr = pos.get(m);
            if (arr) for (const idx of arr) lst.push([idx, m]);
        }
        if (lst.length === 0) continue;
        lst.sort((a, b) => a[0] - b[0]);
        const valSet = [...new Set(lst.map(x => x[1]))].sort((a, b) => a - b);
        const comp = new Map();
        valSet.forEach((v, i) => comp.set(v, i + 1));
        const size = valSet.length;
        const bit = new Array(size + 1).fill(0n);
        const upd = (i, x) => { for (; i <= size; i += i & -i) bit[i] = (bit[i] + x) % MOD; };
        const qry = (i) => { let s = 0n; for (; i > 0; i -= i & -i) s = (s + bit[i]) % MOD; return s; };
        let tot = 0n;
        for (const [idx, v] of lst) {
            const c = comp.get(v);
            const dp = (1n + qry(c - 1)) % MOD;
            tot = (tot + dp) % MOD;
            upd(c, dp);
        }
        cntM[g] = tot;
    }
    const exact = new Array(M + 1).fill(0n);
    for (let g = M; g >= 1; g--) {
        let e = cntM[g];
        for (let m = 2 * g; m <= M; m += g) {
            e = (e - exact[m]) % MOD;
        }
        e = ((e % MOD) + MOD) % MOD;
        exact[g] = e;
    }
    let ans = 0n;
    for (let g = 1; g <= M; g++) {
        ans = (ans + BigInt(g) * exact[g]) % MOD;
    }
    return Number(ans % MOD);
};
